# trace_proxy/main.py
# Sits between Grafana/clients and Tempo. Authenticates the caller,
# looks up their role, queries Tempo, then strips forbidden attrs.

from fastapi import FastAPI, Request, HTTPException, Depends
from fastapi.responses import JSONResponse
import httpx

TEMPO_URL = "http://tempo:3200"

# Attribute allowlist per role (None = block all)
ROLE_ALLOWED_ATTRS: dict[str, set[str]] = {
    "ops-reader":    {"duration_ms", "status", "claude.model", "claude.feature",
                      "claude.retry_count", "claude.input_tokens", "claude.output_tokens"},
    "sre":           {"*"},   # all except content (content never exists)
    "security":      {"*"},
    "support-tier1": {"duration_ms", "status", "claude.feature", "claude.model"},
    "audit-bot":     {"trace_id", "timestamp", "actor", "outcome"},
}

ALWAYS_BLOCK = {"raw_prompt", "raw_response", "prompt_text", "response_text"}


def get_caller_role(request: Request) -> str:
    # In production: validate JWT, extract role claim
    role = request.headers.get("X-User-Role", "")
    if role not in ROLE_ALLOWED_ATTRS:
        raise HTTPException(status_code=403, detail="Unknown role")
    return role


def filter_span(span: dict, allowed: set[str]) -> dict:
    if "*" in allowed:
        # Still strip absolutely forbidden fields
        filtered_attrs = {
            k: v for k, v in span.get("attributes", {}).items()
            if k not in ALWAYS_BLOCK
        }
    else:
        filtered_attrs = {
            k: v for k, v in span.get("attributes", {}).items()
            if k in allowed and k not in ALWAYS_BLOCK
        }
    return {**span, "attributes": filtered_attrs}


app = FastAPI()

@app.get("/api/traces/{trace_id}")
async def get_trace(
    trace_id: str,
    request: Request,
    role: str = Depends(get_caller_role),
):
    async with httpx.AsyncClient() as client:
        resp = await client.get(
            f"{TEMPO_URL}/api/traces/{trace_id}",
            headers={"X-Scope-OrgID": "prod"},
            timeout=10,
        )
    if resp.status_code != 200:
        raise HTTPException(status_code=resp.status_code, detail="Upstream error")

    trace_data = resp.json()
    allowed = ROLE_ALLOWED_ATTRS[role]

    # Filter each span's attributes
    filtered_spans = []
    for batch in trace_data.get("batches", []):
        filtered_resource_spans = []
        for rs in batch.get("scopeSpans", []):
            filtered_spans_inner = [filter_span(s, allowed) for s in rs.get("spans", [])]
            filtered_resource_spans.append({**rs, "spans": filtered_spans_inner})
        filtered_spans.append({**batch, "scopeSpans": filtered_resource_spans})

    return JSONResponse({"batches": filtered_spans})

#!/usr/bin/env python3
# scripts/validate-trace-access-policy.py
import sys
import httpx
import os

GRAFANA_URL   = os.environ["GRAFANA_URL"]
GRAFANA_TOKEN = os.environ["GRAFANA_ADMIN_TOKEN"]

# Expected: only security team can query Tempo-Sensitive
EXPECTED_PERMISSIONS = {
    "Tempo-Sensitive": {"teams": ["security"], "users": []},
    "Tempo-Standard":  {"teams": ["ops-reader", "sre", "support-tier1", "audit-bot"], "users": []},
}

def get_datasource_permissions(name: str) -> dict:
    client = httpx.Client(
        base_url=GRAFANA_URL,
        headers={"Authorization": f"Bearer {GRAFANA_TOKEN}"},
    )
    ds_list = client.get("/api/datasources").json()
    ds = next((d for d in ds_list if d["name"] == name), None)
    if not ds:
        return {}
    perms = client.get(f"/api/access-control/datasources/{ds['uid']}/permissions").json()
    return perms

def main() -> int:
    errors = []
    for ds_name, expected in EXPECTED_PERMISSIONS.items():
        actual = get_datasource_permissions(ds_name)
        actual_teams = {p["team"] for p in actual if p.get("permission") == "Query"}
        expected_teams = set(expected["teams"])
        extra = actual_teams - expected_teams
        missing = expected_teams - actual_teams
        if extra:
            errors.append(f"{ds_name}: unexpected team access: {extra}")
        if missing:
            errors.append(f"{ds_name}: missing required team access: {missing}")

    if errors:
        for e in errors:
            print(f"FAIL: {e}", file=sys.stderr)
        return 1
    print(f"OK: trace datasource permissions match policy")
    return 0

if __name__ == "__main__":
    sys.exit(main())
